import type { DraftEntry } from '@/features/assignments/hooks/useSplitPercent';

export function mergeSeedEntries(
  prev: DraftEntry[],
  seed: DraftEntry[],
  pendingIds: ReadonlySet<string>,
): DraftEntry[] {
  const prevById = new Map(prev.map((e) => [e.id, e]));
  let changed = prev.length !== seed.length;

  const merged = seed.map((seedEntry, i) => {
    const priorAtIndex = prev[i];
    const priorById = prevById.get(seedEntry.id);

    // Keep wholesale if user has an in-flight persist for this row.
    if (priorById && pendingIds.has(seedEntry.id)) {
      if (priorAtIndex !== priorById) changed = true;
      return priorById;
    }

    // Otherwise take seed; check if it differs from what was at this slot.
    if (
      !priorAtIndex ||
      priorAtIndex.id !== seedEntry.id ||
      !priorAtIndex.share.equals(seedEntry.share) ||
      priorAtIndex.locked !== seedEntry.locked ||
      priorAtIndex.displayName !== seedEntry.displayName ||
      priorAtIndex.receiptUserId !== seedEntry.receiptUserId
